以下是一个简单的示例代码，演示了如何将二进制图像转换为H.264流并通过Socket推送到服务器。

```
import java.io.*;
import java.net.*;
import java.awt.image.BufferedImage;
import org.jcodec.api.*;
import org.jcodec.common.io.*;
import org.jcodec.common.model.*;
import org.jcodec.scale.AWTUtil;

public class ImageToH264 {
    private static final int PORT = 8000;
    private static final String SERVER_IP = "192.168.0.1"; // 服务器的IP地址

    public static void main(String[] args) {
        try {
            // 创建Socket连接服务器
            Socket socket = new Socket(SERVER_IP, PORT);

            // 读取二进制图片，转为BufferedImage
            InputStream is = new FileInputStream("image.bin");
            BufferedImage image = ImageIO.read(is);

            // 转换为YUV格式
            Picture yuv = AWTUtil.fromBufferedImage(image, ColorSpace.YUV420);

            // H.264编码
            SequenceEncoder encoder = new SequenceEncoder(new File("video.mp4"));
            encoder.encodeNativeFrame(yuv);
            encoder.finish();

            // 读取编码后的H.264流，通过Socket推送到服务器
            InputStream videoStream = new FileInputStream("video.mp4");
            OutputStream os = socket.getOutputStream();
            byte[] buffer = new byte[1024];
            int length;
            while ((length = videoStream.read(buffer)) != -1) {
                os.write(buffer, 0, length);
            }
            os.flush();

            // 关闭流和Socket
            os.close();
            videoStream.close();
            socket.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
```

需要注意的是，这只是一个简单的示例代码，还有很多细节需要考虑和处理，比如数据的分片和合并，数据的安全性和完整性等等。因此，如果需要将该代码用于实际项目中，还需要进行更深入的研究和开发。

要将二进制图片转换为H.264流，并使用WebSocket将流推送到服务器，可以使用以下步骤：

1. 将二进制图片读取到一个字节数组中。

2. 将字节数组转换为YUV格式。

3. 使用H.264编码器将YUV数据编码为H.264流。

4. 使用Java的WebSocket API将H.264流推送到服务器。

以下是一个简单的示例代码，演示如何将二进制图片转换为H.264流，并使用WebSocket将流推送到服务器：

```
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.net.URI;
import java.net.URISyntaxException;
import java.nio.ByteBuffer;
import javax.imageio.ImageIO;
import org.jcodec.api.SequenceEncoder;
import org.jcodec.common.io.NIOUtils;
import org.jcodec.common.model.ColorSpace;
import org.jcodec.common.model.Picture;
import org.jcodec.scale.AWTUtil;
import org.java_websocket.client.WebSocketClient;
import org.java_websocket.handshake.ServerHandshake;

public class ImageToH264 {

    private static final String SERVER_URI = "ws://example.com/ws"; //服务器的WebSocket地址
    private static final int BUFFER_SIZE = 1024 * 1024;

    public static void main(String[] args) throws IOException, URISyntaxException, InterruptedException {
        // 读取二进制图片到一个字节数组中
        byte[] data = readImageFile("image.bin");

        // 将字节数组转换为BufferedImage
        BufferedImage image = ImageIO.read(new ByteArrayInputStream(data));

        // 将BufferedImage转换为YUV格式
        Picture yuv = AWTUtil.fromBufferedImage(image, ColorSpace.YUV420);

        // 创建H.264编码器
        ByteArrayOutputStream stream = new ByteArrayOutputStream();
        SequenceEncoder encoder = new SequenceEncoder(NIOUtils.writableChannel(stream));
        encoder.encodeNativeFrame(yuv);
        encoder.finish();

        // 获取编码后的H.264流
        byte[] h264Data = stream.toByteArray();

        // 创建WebSocket连接到服务器
        WebSocketClient client = new WebSocketClient(new URI(SERVER_URI)) {
            @Override
            public void onOpen(ServerHandshake handshakedata) {
                System.out.println("WebSocket opened");
            }

            @Override
            public void onClose(int code, String reason, boolean remote) {
                System.out.println("WebSocket closed: " + reason);
            }

            @Override
            public void onError(Exception ex) {
                ex.printStackTrace();
                System.out.println("WebSocket error");
            }

            @Override
            public void onMessage(ByteBuffer buffer) {
                // 不需要处理服务器返回的消息
            }
        };
        client.connect();

        // 推送H.264流到服务器
        int position = 0;
        while (position < h264Data.length) {
            int size = Math.min(BUFFER_SIZE, h264Data.length - position);
            client.send(ByteBuffer.wrap(h264Data, position, size));
            position += size;
        }

        // 等待所有数据都发送完成后关闭WebSocket连接
        while (!client.isClosing() && !client.isClosed() && client.isOpen()) {
            Thread.sleep(1000);
        }
        client.close();
    }

    private static byte[] readImageFile(String filename) throws IOException {
        InputStream is = new FileInputStream(filename);
        byte[] buffer = new byte[is.available()];
        is.read(buffer);
        is.close();
        return buffer;
    }
}
```

